import axios from "axios";
import { useEffect, useRef, useState } from "react";
import { Link, useNavigate, useSearchParams } from "react-router-dom";
import { useCart } from "./CartContext";
import { timeAgo } from "../utils/timeAgo";
import "./review.css";
import hashids from "../utils/hashids";

const PackageDetails = () => {
  const [reviews, setReviews] = useState([]);
  const [reviewData, setReviewData] = useState({ rating: 0, review: "" });
  const [submitting, setSubmitting] = useState(false);
  const { activeTab } = useCart();
  const [loading, setLoading] = useState(true);
  const [dataLoading, setDataLoading] = useState(true); // Add data loading state

  const [packageData, setPackageData] = useState(null);

  const [searchParams] = useSearchParams();
  const id = searchParams.get("id");
  const [decodedID, setDecodedID] = useState("");

  // Safe encode function
  const safeEncodeId = (id) => {
    if (!id) return '';
    try {
      return hashids.encodeHex(id.toString());
    } catch (error) {
      console.error("Error encoding ID:", error);
      return '';
    }
  };

  useEffect(() => {
    const fetchDecryptedID = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/decrypt/${id}`
        );
        setDecodedID(response.data.decodedId);
      } catch (error) {
        console.error("Failed to fetch decrypted ID:", error);
      }
    };

    if (id) {
      fetchDecryptedID();
    }
  }, [id]);

  useEffect(() => {
    const fetchPackage = async () => {
      try {
        setDataLoading(true);
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/packages/single/${decodedID}`,
        );
        setPackageData(response.data);
      } catch (error) {
        console.error("Error fetching package data:", error);
      } finally {
        setDataLoading(false);
      }
    };
    
    if (decodedID) {
      fetchPackage();
    }
  }, [decodedID]);

  const [recentPackage, setRecentPackage] = useState([]);

  useEffect(() => {
    const fetchRecentPackage = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/packages`,
        );
        // Handle different response structures
        if (response.data.packages) {
          setRecentPackage(response.data.packages);
        } else if (Array.isArray(response.data)) {
          setRecentPackage(response.data);
        }
      } catch (error) {
        console.error("Error in fetching the recent package data", error);
      }
    };

    fetchRecentPackage();
  }, []);

  const { addToCart } = useCart();
  const navigate = useNavigate();
  const { cartItems } = useCart();

  const isPackageInCart = (pkgId) => {
    return cartItems.some(
      (item) => item.type === "package" && item._id === pkgId,
    );
  };

  const handleBookNowPackage = async (packageId, fromPage) => {
    if (isPackageInCart(packageId)) {
      navigate("/cart", { state: { from: fromPage } });
      return;
    }

    try {
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/packages/single/${packageId}`,
      );
      const selectedPackage = {
        ...response.data,
        type: "package",
      };

      addToCart(selectedPackage);
      navigate("/cart", { state: { from: fromPage } });
    } catch (error) {
      console.error("Error adding package to cart", error);
    }
  };

  // doctor detail pop up
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [showDoctorModal, setShowDoctorModal] = useState(false);

  const handleDoctorClick = (doctor) => {
    setSelectedDoctor(doctor);
    setShowDoctorModal(true);
  };

  const closeDoctorModal = () => {
    setShowDoctorModal(false);
    setSelectedDoctor(null);
  };

  const modalRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (
        modalRef.current &&
        !modalRef.current.contains(event.target) &&
        showDoctorModal
      ) {
        showDoctorModal(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);

    if (showDoctorModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.body.style.overflow = "auto";
    };
  }, [showDoctorModal]);

  const handleRatingClick = (rating) => {
    setReviewData((prev) => ({ ...prev, rating }));
  };

  const handleReviewSubmit = async (e) => {
    e.preventDefault();

    if (
      (!reviewData.rating || reviewData.rating <= 0) &&
      !reviewData.review.trim()
    ) {
      alert("Please provide rating or review");
      return;
    }

    const userId = localStorage.getItem("userId");
    if (!userId) {
      localStorage.setItem(
        "pendingReview",
        JSON.stringify({
          serviceId: id,
          data: reviewData,
        }),
      );
      navigate("/review-login");
      return;
    }

    setSubmitting(true);
    try {
      const payload = {
        userId,
        packageId: decodedID,
        ...(reviewData.rating > 0 && { rating: reviewData.rating }),
        ...(reviewData.review.trim() && { review: reviewData.review.trim() }),
      };
      await axios.post(
        `${process.env.REACT_APP_BACKEND_URL}/api/review/createReveiw/package`,
        payload,
      );
      alert("Review submitted successfully!");
      setReviewData({ rating: 0, review: "" });
      localStorage.removeItem("pendingReview");
    } catch (error) {
      console.error("Error submitting review:", error);
      alert(
        error?.response?.data?.message ||
          "Failed to submit review. Please try again.",
      );
    } finally {
      setSubmitting(false);
    }
  };

  useEffect(() => {
    const fetchReviews = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/review/package/${decodedID}`,
        );
        setReviews(res.data.reviews || []);
      } catch (err) {
        console.error("Error fetching reviews:", err);
      } finally {
        setLoading(false);
      }
    };

    if (decodedID) {
      fetchReviews();
    }
  }, [decodedID]);

  const createSlug = (text) => {
    if (!text) return '';
    return text
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '');
  };

  // Show loading state while data is being fetched
  if (dataLoading) {
    return (
      <div className="container text-center py-5">
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
        <p className="mt-2">Loading package details...</p>
      </div>
    );
  }

  // Show error state if no package data
  if (!packageData) {
    return (
      <div className="container text-center py-5">
        <h5 className="text-muted">Package not found</h5>
        <Link to="/all-package" className="btn btn-main mt-3">
          Browse Packages
        </Link>
      </div>
    );
  }

  const packageDetails = packageData?.package || {};

  return (
    <div className="product-details mt-32 padding-b-120">
      <div className="container container-two">
        <div className="row gy-4">
          <div className="col-lg-8">
            <div className="tab-content" id="pills-tabContent">
              <div
                className="tab-pane fade show active"
                id="pills-product-details"
                role="tabpanel"
                aria-labelledby="pills-product-details-tab"
                tabIndex={0}
              >
                {/* Product Details Content Start */}
                <div className="product-details">
                  <div className="product-details__thumb"></div>

                  <p className="product-details__desc">
                    {packageDetails?.description}
                  </p>
                  
                  <div>
                    <h6 className="product-details__title mb-3">
                      Services Included
                    </h6>
                    <ul
                      className="product-list"
                      style={{
                        display: "grid",
                        gridTemplateColumns: "1fr 1fr",
                        gap: "0px 20px",
                        paddingLeft: "17px",
                        margin: 0,
                      }}
                    >
                      {packageDetails?.services?.map((service, index) => (
                        <li
                          key={service?._id || index}
                          className="product-list__item"
                        >
                          {service?.serviceName || "Service"}
                        </li>
                      ))}
                    </ul>
                  </div>
                  <br />

                  <div className="product-details__item">
                    <h2 className="product-details__title mb-3">Facilities</h2>
                    {packageDetails?.centre?.availableFacilities?.length > 0 ? (
                      <ul
                        className="product-list"
                        style={{
                          display: "grid",
                          gridTemplateColumns: "1fr 1fr",
                          gap: "0px 20px",
                          paddingLeft: "17px",
                          margin: 0,
                        }}
                      >
                        {packageDetails?.centre?.availableFacilities?.map(
                          (facility, index) => (
                            <li
                              className="product-list__item"
                              key={index}
                              style={{ margin: "3px 0" }}
                            >
                              {facility}
                            </li>
                          ),
                        )}
                      </ul>
                    ) : (
                      <p>Facilities not Mentioned</p>
                    )}
                  </div>

                  <div className="product-details__item">
                    <h2 className="product-details__title mb-3">
                      Insurance Availability
                    </h2>
                    {packageDetails?.centre?.availableInsurance?.length > 0 ? (
                      <ul
                        className="product-list"
                        style={{
                          display: "grid",
                          gridTemplateColumns: "1fr 1fr",
                          gap: "0px 20px",
                          paddingLeft: "17px",
                          margin: 0,
                        }}
                      >
                        {packageDetails?.centre?.availableInsurance?.map(
                          (insurance, index) => (
                            <li
                              className="product-list__item"
                              key={index}
                              style={{ margin: "3px 0" }}
                            >
                              {insurance}
                            </li>
                          ),
                        )}
                      </ul>
                    ) : (
                      <p>No Insurance Available</p>
                    )}
                  </div>
                </div>

                {/* Review section start */}
                <div className="review-section d-none d-lg-block">
                  <div className="review-card">
                    <h5 className="review-title">Write a Review</h5>

                    <form onSubmit={handleReviewSubmit}>
                      <div className="review-group">
                        <label>
                          Rating <span>(Optional)</span>
                        </label>

                        <div className="review-stars">
                          {[1, 2, 3, 4, 5].map((star) => (
                            <span
                              key={star}
                              className={`review-star ${
                                star <= reviewData.rating ? "filled" : ""
                              }`}
                              onClick={() => handleRatingClick(star)}
                            >
                              ★
                            </span>
                          ))}
                        </div>

                        <small>Click to rate (1–5 stars) – Optional</small>
                      </div>

                      <div className="review-group">
                        <label>Your Review</label>

                        <textarea
                          placeholder="Share your experience with this service..."
                          value={reviewData.review}
                          onChange={(e) =>
                            setReviewData((prev) => ({
                              ...prev,
                              review: e.target.value,
                            }))
                          }
                          rows="4"
                          maxLength="1000"
                        />

                        <small>
                          {reviewData.review.length}/1000 characters
                        </small>
                      </div>

                      <button
                        type="submit"
                        className="review-submit"
                        disabled={
                          submitting ||
                          (!reviewData.rating && !reviewData.review.trim())
                        }
                      >
                        {submitting ? "Submitting..." : "Submit Review"}
                      </button>
                    </form>
                  </div>
                </div>
                {/* Review section end */}
              </div>

              <div
                className={`tab-pane fade ${
                  activeTab === "ratings" ? "show active" : ""
                }`}
                id="pills-rating"
                role="tabpanel"
                aria-labelledby="pills-rating-tab"
                tabIndex={0}
              >
                <div className="product-review-wrapper">
                  {loading ? (
                    <p>Loading reviews...</p>
                  ) : reviews.length > 0 ? (
                    reviews.map((review) => (
                      <div className="product-review" key={review._id}>
                        <div className="product-review__top flx-between">
                          <div className="product-review__rating flx-align">
                            <div className="d-flex align-items-center gap-1">
                              <ul className="star-rating">
                                {[1, 2, 3, 4, 5].map((star) => (
                                  <li
                                    key={star}
                                    className="star-rating__item font-11"
                                    style={{
                                      color:
                                        star <= review.rating
                                          ? "#ffc107"
                                          : "#ddd",
                                    }}
                                  >
                                    <i className="fas fa-star" />
                                  </li>
                                ))}
                              </ul>
                              <span className="star-rating__text text-body">
                                {typeof review.rating === "number"
                                  ? review.rating.toFixed(1)
                                  : "0.0"}
                              </span>
                            </div>
                          </div>

                          <div className="product-review__date">
                            by{" "}
                            <span className="product-review__user text-primary">
                              {review.userName}
                            </span>{" "}
                            {timeAgo(review.updatedAt)}
                          </div>
                        </div>

                        <div className="product-review__body">
                          <p className="product-review__desc">
                            {review.review}
                          </p>
                        </div>
                      </div>
                    ))
                  ) : (
                    <p className="text-muted">
                      No reviews found for this package.
                    </p>
                  )}
                </div>
              </div>
            </div>
          </div>

          {activeTab !== "ratings" && (
            <div className="col-lg-4">
              <div className="product-sidebar section-bg">
                <div className="product-sidebar__top position-relative flx-between gap-1">
                  <button type="button" className="font-heading font-18">
                    Book Appointment
                  </button>

                  <div className="flx-align gap-2">
                    <h6 className="product-item__price text-success mb-0">
                      ₹{packageDetails?.totalPrice}
                    </h6>
                    {packageDetails?.discountPrice ? (
                      <span className="product-item__prevPrice text-decoration-line-through">
                        ₹{packageDetails?.actualPrice}
                      </span>
                    ) : null}
                  </div>
                </div>

                <Link
                  to="/cart"
                  state={{ 
                    from: window.location.pathname + window.location.search 
                  }}
                  className="btn btn-main d-flex w-100 justify-content-center align-items-center gap-2 pill px-sm-5 mt-32"
                  onClick={() => {
                    if (decodedID) {
                      handleBookNowPackage(
                        decodedID,
                        window.location.pathname + window.location.search
                      );
                    }
                  }}
                >
                  <img src="/assets/images/icons/add-to-cart.svg" alt=""  loading="lazy"/>
                  Book Now
                </Link>

                {/* Author Details Start */}
                {packageDetails?.doctors?.length > 0 && (
                  <div className="author-details">
                    <div
                      key={packageDetails.doctors[0]._id}
                      className="d-flex align-items-center gap-2 mb-3"
                    >
                      <div className="author-details__thumb flex-shrink-0">
                        <img
                          src={packageDetails.doctors[0].profilePhoto}
                          alt={packageDetails.doctors[0].name}
                          style={{
                            borderRadius: "50%",
                            width: "73px",
                            height: "70px",
                            objectFit: "cover",
                            cursor: "pointer",
                          }}
                          onClick={() =>
                            handleDoctorClick(packageDetails.doctors[0])
                          }
                        />
                      </div>

                      <div className="author-details__content">
                        <h6 className="author-details__name font-18 mb-2">
                          <button
                            className="p-0 link text-decoration-none border-0 bg-transparent"
                            style={{
                              fontSize: "inherit",
                              fontWeight: "inherit",
                              color: "black",
                              cursor: "pointer",
                            }}
                            onClick={() =>
                              handleDoctorClick(packageDetails.doctors[0])
                            }
                          >
                            {packageDetails.doctors[0].name}
                          </button>
                        </h6>
                        <div
                          style={{
                            display: "-webkit-box",
                            WebkitBoxOrient: "vertical",
                            WebkitLineClamp: 4,
                            overflow: "hidden",
                            maxHeight: "5.9rem",
                            textOverflow: "ellipsis",
                            whiteSpace: "normal",
                          }}
                        >
                          <span className="text">
                            {packageDetails.doctors[0].specialization}
                          </span>
                          <span className="text">
                            {packageDetails.doctors[0].qualification}
                          </span>
                        </div>
                        <div>
                          <button
                            className="text-primary text-decoration-underline"
                            style={{ background: "none", border: "none", cursor: "pointer" }}
                            onClick={() =>
                              handleDoctorClick(packageDetails.doctors[0])
                            }
                          >
                            View More
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
                {/* Author Details End */}

                {/* Meta Attribute List Start */}
                {packageDetails?.slots?.length > 0 && (
                  <ul className="meta-attribute">
                    <li className="meta-attribute__item">
                      <span className="name">Availability Time</span>
                      <span className="details d-flex flex-wrap gap-2">
                        {packageDetails?.slots?.map((slot) => (
                          <p key={slot._id}>
                            {slot.day}: {slot.from} - {slot.to}
                          </p>
                        ))}
                      </span>
                    </li>
                  </ul>
                )}
                
                <span className="details" style={{ color: "black" }}>
                  Doctor Report Uploading Time:
                </span>{" "}
                <span className="details">
                  {packageDetails?.reportTiming}
                </span>

                {packageDetails?.centre?.googleMapLink && (
                  <div
                    style={{
                      marginTop: "20px",
                      width: "100%",
                      maxWidth: "800px",
                      height: "300px",
                      borderRadius: "8px",
                      overflow: "hidden",
                      boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                    }}
                    dangerouslySetInnerHTML={{
                      __html: packageDetails?.centre?.googleMapLink,
                    }}
                  />
                )}

                <div className="review-section d-block d-lg-none">
                  <div className="review-card">
                    <h5 className="review-title">Write a Review</h5>

                    <form onSubmit={handleReviewSubmit}>
                      <div className="review-group">
                        <label>
                          Rating <span>(Optional)</span>
                        </label>

                        <div className="review-stars">
                          {[1, 2, 3, 4, 5].map((star) => (
                            <span
                              key={star}
                              className={`review-star ${
                                star <= reviewData.rating ? "filled" : ""
                              }`}
                              onClick={() => handleRatingClick(star)}
                            >
                              ★
                            </span>
                          ))}
                        </div>

                        <small>Click to rate (1–5 stars) – Optional</small>
                      </div>

                      <div className="review-group">
                        <label>Your Review</label>

                        <textarea
                          placeholder="Share your experience with this service..."
                          value={reviewData.review}
                          onChange={(e) =>
                            setReviewData((prev) => ({
                              ...prev,
                              review: e.target.value,
                            }))
                          }
                          rows="4"
                          maxLength="1000"
                        />

                        <small>
                          {reviewData.review.length}/1000 characters
                        </small>
                      </div>

                      <button
                        type="submit"
                        className="review-submit"
                        disabled={
                          submitting ||
                          (!reviewData.rating && !reviewData.review.trim())
                        }
                      >
                        {submitting ? "Submitting..." : "Submit Review"}
                      </button>
                    </form>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Doctor Modal */}
      {showDoctorModal && selectedDoctor && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: "rgba(0,0,0,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
        >
          <div
            ref={modalRef}
            style={{
              backgroundColor: "#fff",
              borderRadius: "10px",
              maxWidth: "800px",
              width: "95%",
              maxHeight: "95vh",
              boxShadow: "0 0 10px rgba(0,0,0,0.3)",
              position: "relative",
              overflowY: "auto",
              paddingBottom: "20px",
            }}
          >
            <div
              style={{
                backgroundColor: "#3a3a3a",
                color: "#fff",
                padding: "15px 20px",
                fontSize: "18px",
                fontWeight: "bold",
                position: "sticky",
                top: 0,
                zIndex: 1,
              }}
            >
              <i className="fas fa-user-md me-2"></i> Doctor Details
              <button
                onClick={closeDoctorModal}
                style={{
                  position: "absolute",
                  top: "10px",
                  right: "10px",
                  background: "transparent",
                  border: "none",
                  fontSize: "22px",
                  color: "#fff",
                  cursor: "pointer",
                }}
              >
                &times;
              </button>
            </div>

            <div
              style={{
                padding: "20px",
                display: "flex",
                flexWrap: "wrap",
                gap: "20px",
                color: "#333",
              }}
            >
              <div style={{ flex: 1, minWidth: "250px", textAlign: "center" }}>
                <img
                  src={selectedDoctor.profilePhoto}
                  alt={selectedDoctor.name}
                  style={{
                    width: "150px",
                    height: "150px",
                    objectFit: "cover",
                    borderRadius: "50%",
                    border: "4px solid #e3f2fd",
                    boxShadow: "0 0 5px rgba(0,0,0,0.3)",
                  }}
                />
              </div>

              <div style={{ flex: 2, minWidth: "250px" }}>
                <h4 className="mb-3 fw-bold">{selectedDoctor.name}</h4>

                {selectedDoctor.specialization && (
                  <div style={{ marginBottom: "10px" }}>
                    <i className="fas fa-stethoscope me-2"></i>
                    <strong>Specialization:</strong>&nbsp;
                    <br />
                    <span>{selectedDoctor.specialization}</span>
                  </div>
                )}

                {selectedDoctor.qualification && (
                  <div style={{ marginBottom: "10px" }}>
                    <i className="fas fa-graduation-cap me-2"></i>
                    <strong>Qualification:</strong>&nbsp;
                    <span>{selectedDoctor.qualification}</span>
                  </div>
                )}

                {selectedDoctor.experience && (
                  <div style={{ marginBottom: "10px" }}>
                    <i className="fas fa-calendar-alt me-2"></i>
                    <strong>Experience:</strong>&nbsp;
                    <br />
                    <span>{selectedDoctor.experience}</span>
                  </div>
                )}

                {selectedDoctor.aboutDoctor && (
                  <div style={{ marginBottom: "10px" }}>
                    <i className="fas fa-info-circle me-2 mt-1"></i>
                    <strong>About:</strong>
                    <p style={{ marginTop: "5px" }}>
                      {selectedDoctor.aboutDoctor}
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PackageDetails;